// Même logique que v1 — summaryRecipient depuis env si dispo
let limit = 10;
const summaryRecipient = (typeof process !== 'undefined' && process.env?.CLIENT_SUMMARY_RECIPIENT) || (typeof process !== 'undefined' && process.env?.SUMMARY_RECIPIENT_EMAIL) || 'ouat.abou34@outlook.fr';
try {
  const allItems = $input.all();
  for (const item of allItems) {
    const bodyLimit = item.json?.body?.limit;
    if (bodyLimit !== undefined && bodyLimit !== null) {
      const parsed = parseInt(String(bodyLimit), 10);
      if (!isNaN(parsed)) limit = Math.max(1, Math.min(50, parsed));
      break;
    }
  }
} catch(e) {}
return [{ json: { maxEmails: limit, summaryRecipient, openAiModel: 'gpt-4o-mini', lookbackHours: 8 } }];

// Adapté pour le noeud natif microsoftOutlook (un item = un email)
const cfg = $('Configuration').first().json;
const allItems = $input.all();

// Guard 1 : alwaysOutputData renvoie {} si 0 email
if (allItems.length === 1 && !allItems[0].json.id && !allItems[0].json.subject) {
  return [{ json: { emails: [], skipped: [], no_emails: true, runAt: new Date().toISOString() } }];
}
// Guard 2 : erreur noeud natif avec continueOnFail
if (allItems.length === 1 && allItems[0].json?.error) {
  return [{ json: { emails: [], skipped: [], no_emails: true, runAt: new Date().toISOString() } }];
}

// Le noeud natif renvoie 1 item par email (pas items[0].json.value)
const messages = allItems.map(i => i.json);

const excludedSenderFragments = [
  'no-reply', 'noreply', 'newsletter', 'notification', 'notifications',
  'marketing', 'facebookmail', 'linkedin', 'microsoft-noreply'
];
const excludedSenderDomains = [
  'substack.com', 'mailchimp.com', 'sendgrid.net', 'constantcontact.com',
  'hubspot.com', 'mailerlite.com', 'sendinblue.com', 'klaviyo.com', 'brevo.com'
];
const excludedSubjectFragments = [
  'newsletter', 'desabonnement', 'désabonnement', 'promotion',
  'notification automatique', 'alerte automatique', 'absence du bureau', 'automatic reply'
];
const cutoff = new Date(Date.now() - Number(cfg.lookbackHours || 8) * 60 * 60 * 1000);
const prepared = [];
const skipped = [];

for (const m of messages) {
  const categories = Array.isArray(m.categories) ? m.categories : [];
  // Le noeud natif expose from.emailAddress.address (même format que Graph API)
  const sender = (m.from?.emailAddress?.address || '').toLowerCase();
  const senderName = m.from?.emailAddress?.name || '';
  const subject = m.subject || '(sans objet)';
  const subjectLower = subject.toLowerCase();
  const receivedAt = new Date(m.receivedDateTime || 0);

  const alreadyProcessed = categories.includes('IA - Traite') || categories.includes('IA - Exclu');
  const excludedBySender = excludedSenderFragments.some(x => sender.includes(x)) ||
    excludedSenderDomains.some(d => sender.endsWith('@' + d) || sender.includes('.' + d));
  const excludedBySubject = excludedSubjectFragments.some(x => subjectLower.includes(x));
  const tooOld = Number.isFinite(receivedAt.getTime()) && receivedAt < cutoff;

  if (alreadyProcessed || excludedBySender || excludedBySubject || tooOld) {
    skipped.push({
      id: m.id, subject, sender,
      reason: alreadyProcessed ? 'deja_traite' : excludedBySender ? 'expediteur_exclu' : excludedBySubject ? 'objet_exclu' : 'trop_ancien'
    });
    continue;
  }

  // bodyPreview = snippet court (le noeud natif n'inclut pas le HTML complet par défaut)
  const bodyText = (m.body?.content || m.bodyPreview || '')
    .replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 4000);

  prepared.push({
    id: m.id, subject, sender, senderName,
    receivedDateTime: m.receivedDateTime,
    importance: m.importance, categories,
    hasAttachments: Boolean(m.hasAttachments),
    webLink: m.webLink, bodyText
  });
}

return [{ json: { emails: prepared, skipped, no_emails: prepared.length === 0, runAt: new Date().toISOString() } }];

const MOTS_URGENCE = [
  'assignation', 'convocation', 'audience', 'jugement', 'ordonnance',
  'conclusions', 'appel', 'pourvoi', 'signification', 'huissier',
  'délai', 'delai', 'échéance', 'echeance', 'prescription', 'forclusion',
  'urgent', 'urgence', 'impératif', 'imperatif', 'immédiat', 'immediat',
  'mise en demeure', 'relance', 'injonction', 'sommation',
  'arrêt', 'arret', 'décision', 'decision', 'notification'
];
const source = $input.first().json;
const emails_enrichis = (source.emails || []).map(email => {
  const texte = `${email.subject || ''} ${email.bodyText || ''}`.toLowerCase();
  const matches = MOTS_URGENCE.filter(kw => texte.includes(kw));
  return { ...email, keyword_urgence: matches.length > 0, keyword_matches: matches };
});
return [{ json: { ...source, emails: emails_enrichis, nb_pre_urgents: emails_enrichis.filter(e => e.keyword_urgence).length } }];

// Construit le prompt complet (system + emails) pour le LLM Chain
const emails = $('Pré-détection keywords').first().json.emails || [];
const systemPrompt = `Tu classes des emails pour un cabinet d avocat. Reponds uniquement en JSON valide (pas de markdown). N invente pas de faits. Un email peut avoir plusieurs etiquettes. Ne propose jamais un envoi automatique. Les brouillons doivent rester prudents et validables. Si l expediteur est un newsletter, service d abonnement ou email commercial (Substack, Mailchimp, promotions, offres), classe toujours urgence=faible et action=classer.`;
const userPrompt = JSON.stringify({
  consigne: 'Classe chaque email. Champs attendus: id, urgence=haute|moyenne|faible, interlocuteur=client|confrere|juridiction|expert|assureur|notaire|mandant_immobilier|administration|autre|indetermine, action=repondre|lire|relancer|classer|aucune, echeance_detectee=true|false, date_echeance=YYYY-MM-DD ou null, resume=phrase courte, raison_urgence=phrase courte ou vide, brouillon_recommande=true|false, brouillon=texte court ou vide. Ajoute aussi global_summary en 5 lignes maximum.',
  criteres_urgence: ['date limite proche','audience','convocation','delai','assignation','ordonnance','jugement','conclusions','message juridiction','demande de signature rapide','relance avec delai','termes urgent ou imperatif'],
  emails
});
return [{ json: { ...$('Pré-détection keywords').first().json, classificationPrompt: `${systemPrompt}\n\n${userPrompt}` } }];

// Adapté pour la sortie du chainLlm : $json.text (pas choices[0].message.content)
const source = $('Préparer lot emails').first().json;
const raw = $input.first().json.text || '{}';
let parsed;
try {
  // Extraire JSON si entouré de markdown ```json ... ```
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch(e) {
  parsed = { emails: [], global_summary: 'Erreur de parsing de la réponse IA. ' + String(e) };
}

const originalsById = new Map((source.emails || []).map(e => [e.id, e]));
const analyses = (parsed.emails || []).map(a => {
  const original = originalsById.get(a.id) || {};
  const categories = new Set(original.categories || []);
  const urgency = String(a.urgence || 'faible').toLowerCase();
  const action = String(a.action || 'aucune').toLowerCase();
  if (urgency === 'haute') categories.add('IA - Urgent');
  if (action === 'repondre') categories.add('IA - A repondre');
  if (action === 'relancer') categories.add('IA - Relance');
  if (action === 'lire') categories.add('IA - A lire');
  if (action === 'classer') categories.add('IA - A classer');
  if (a.echeance_detectee) categories.add('IA - Echeance');
  categories.add('IA - Traite');
  return { ...original, analyse: a, nextCategories: Array.from(categories) };
});

const urgent = analyses.filter(x => x.analyse?.urgence === 'haute');
const repondre = analyses.filter(x => x.analyse?.action === 'repondre');
const echeances = analyses.filter(x => x.analyse?.echeance_detectee);
const drafts = analyses.filter(x => x.analyse?.brouillon_recommande && x.analyse?.brouillon);

function line(x) {
  const a = x.analyse || {};
  return `• ${x.senderName || x.sender} | ${x.subject || '(sans objet)'} | ${a.resume || ''}${a.raison_urgence ? ' — ' + a.raison_urgence : ''}`;
}

const summaryText = [
  `🤖 Synthèse Outlook V2 (LangChain) — ${new Date().toLocaleString('fr-FR')}`,
  `Analysés : ${analyses.length} | Ignorés : ${(source.skipped || []).length}`,
  '',
  '🚨 Urgents',
  urgent.length ? urgent.map(line).join('\n') : '• Aucun email urgent.',
  '',
  '📩 À répondre',
  repondre.length ? repondre.map(line).join('\n') : '• Aucune réponse prioritaire.',
  '',
  '📅 Échéances détectées',
  echeances.length ? echeances.map(x => `• ${x.analyse.date_echeance || 'date à confirmer'} | ${x.senderName || x.sender} | ${x.subject || '(sans objet)'} | ${x.analyse.resume || ''}`).join('\n') : '• Aucune échéance.',
  '',
  '📝 Brouillons proposés',
  drafts.length ? drafts.map(x => `• ${x.senderName || x.sender} | ${x.subject || '(sans objet)'}`).join('\n') : '• Aucun brouillon.',
  '',
  '📋 Synthèse générale',
  parsed.global_summary || '• Rien à signaler.'
].join('\n');

const emails_structured = analyses.map(a => ({
  id: a.id,
  from: a.sender || '',
  from_name: a.senderName || (a.sender || '').split('@')[0],
  from_email: a.sender || '',
  subject: a.subject || '(sans objet)',
  snippet: (a.bodyText || '').slice(0, 300),
  urgence: a.analyse?.urgence || 'faible',
  action: a.analyse?.action || 'lire',
  resume: a.analyse?.resume || '',
  echeance: a.analyse?.echeance_detectee ? (a.analyse?.date_echeance || null) : null,
  source: 'outlook'
}));

return [{ json: { analyses, summaryText, processedCount: analyses.length, skippedCount: (source.skipped || []).length, urgentCount: urgent.length, repondreCount: repondre.length, emails_structured } }];

const analyses = $input.first().json.analyses || [];
return analyses.map(x => ({
  json: {
    id: x.id,
    patchUrl: `https://graph.microsoft.com/v1.0/me/messages/${x.id}`,
    categories: x.nextCategories,
    subject: x.subject,
    sender: x.sender
  }
}));

