const analyses = $('Parser analyse IA').first().json.analyses || [];
const drafts = analyses.filter(a => a.analyse?.brouillon_recommande && a.analyse?.brouillon?.trim());
if (drafts.length === 0) return [];
return drafts.map(a => ({
  json: {
    subject: `RE: ${a.subject || ''}`,
    body: a.analyse.brouillon,
    to: a.sender || ''
  }
}));

